const crypto = require('crypto');
const secret = process.env.CAL_WEBHOOK_SECRET;
if (!secret) throw new Error('CAL_WEBHOOK_SECRET not set');
const item = items[0].json;
const rawBody = typeof item.body === 'string' ? item.body : JSON.stringify(item.body);
const h = item.headers || {};
const received = h['x-cal-signature-256'] || h['X-Cal-Signature-256'];
if (!received) throw new Error('Missing X-Cal-Signature-256');
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
const a = Buffer.from(expected), b = Buffer.from(String(received));
if (!(a.length === b.length && crypto.timingSafeEqual(a, b))) throw new Error('Invalid signature');
const parsed = typeof item.body === 'string' ? JSON.parse(item.body) : item.body;
return [{ json: parsed }];

// Idempotency: skip if this (uid:reminder) was already handled.
const data = $getWorkflowStaticData('global');
data.seen = data.seen || {};
const key = items[0].json.payload.uid + ':reminder';
if (data.seen[key]) return [];
data.seen[key] = true;
// Compute reminder time = startTime - REMINDER_HOURS (default 24h).
const hours = Number(process.env.REMINDER_HOURS || 24);
const start = new Date(items[0].json.payload.startTime);
const remindAt = new Date(start.getTime() - hours * 3600 * 1000).toISOString();
return [{ json: { ...items[0].json, remindAt } }];
